class MyExtensionExt:
    def __init__(self, ownerComp):
        self.ownerComp = ownerComp
        # Initialize any state
        self._count = 0

    @property
    def Count(self):
        """Read-only property for current count."""
        return self._count

    def Increment(self):
        """Increment the counter and update display."""
        self._count += 1
        self.ownerComp.par.Displaycount = self._count
        return self._count

    def Reset(self):
        """Reset the counter to zero."""
        self._count = 0
        self.ownerComp.par.Displaycount = 0

# Example extension that uses custom parameters
class ConfigurableExt:
    def __init__(self, ownerComp):
        self.ownerComp = ownerComp

    @property
    def Speed(self):
        """Get the configured speed from custom parameter."""
        return self.ownerComp.par.Speed.eval()

    def Update(self):
        """Called each frame - uses custom parameters."""
        speed = self.ownerComp.par.Speed.eval()
        scale = self.ownerComp.par.Scale.eval()
        # Apply to child operators
        self.ownerComp.op('transform1').par.r += speed
        self.ownerComp.op('transform1').par.sx = scale
